# Terraform: read current region from provider
data "aws_region" "current" {}

resource "aws_s3_bucket" "app" {
  bucket = "my-app-${data.aws_region.current.name}-${data.aws_caller_identity.current.account_id}"
}

# Multi-region with aliased providers
provider "aws" {
  region = "us-east-1"
  alias  = "primary"
}

provider "aws" {
  region = "eu-west-1"
  alias  = "dr"
}

resource "aws_instance" "primary_web" {
  provider = aws.primary
  ami      = data.aws_ami.amazon_linux_primary.id
  # ...
}

resource "aws_instance" "dr_web" {
  provider = aws.dr
  ami      = data.aws_ami.amazon_linux_dr.id
  # ...
}

{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "AllowEC2OnlyInEU",
      "Effect": "Allow",
      "Action": "ec2:*",
      "Resource": "*",
      "Condition": {
        "StringEquals": {
          "aws:RequestedRegion": [
            "eu-west-1",
            "eu-central-1",
            "eu-west-2"
          ]
        }
      }
    },
    {
      "Sid": "AllowGlobalServices",
      "Effect": "Allow",
      "Action": [
        "iam:*",
        "cloudfront:*",
        "route53:*",
        "s3:GetBucketLocation"
      ],
      "Resource": "*"
      // No region condition — these services have no regional endpoint
    }
  ]
}
